// urlHost extracts the host from a URL, returning the original string if parsing fails.
func urlHost(rawURL string) string {
	if u, err := url.Parse(rawURL); err == nil && u.Host != "" {
		return u.Host
	}
	return rawURL
}

// toolCallDisplayText returns a plain text description of the tool call.
// Used in contexts where HTML is not appropriate.
func toolCallDisplayText(call models.LLMToolCall) string {
	if params := call.BrowserNavigateParams(); params != nil {
		return fmt.Sprintf("Browsing %q", urlHost(params.URL))
	}
	if params := call.SearchRequestParams(); params != nil {
		return fmt.Sprintf("Searching for %q", params.Query)
	}
	switch call.Name {
	case models.LLMToolNameBrowserClick:
		return "Clicking on a link"
	case models.LLMToolNameBrowserWait:
		return "Waiting for the page to load"
	default:
		return fmt.Sprintf("Running %s", call.Name)
	}
}

